import{_ as t,o,c as a,a2 as r}from"./chunks/framework.ufzXw1qY.js";const p=JSON.parse('{"title":"OpenSIN Bridge — Chrome Extension","description":"Full-featured Chrome extension for browser automation, cookie management, and AI agent integration","frontmatter":{"title":"OpenSIN Bridge — Chrome Extension","description":"Full-featured Chrome extension for browser automation, cookie management, and AI agent integration"},"headers":[],"relativePath":"bridges/chrome-extension.md","filePath":"bridges/chrome-extension.md"}'),n={name:"bridges/chrome-extension.md"};function d(i,e,s,c,l,h){return o(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="opensin-bridge-—-chrome-extension" tabindex="-1">OpenSIN Bridge — Chrome Extension <a class="header-anchor" href="#opensin-bridge-—-chrome-extension" aria-label="Permalink to &quot;OpenSIN Bridge — Chrome Extension&quot;">​</a></h1><p><strong>Version:</strong> 2.5.0<br><strong>Status:</strong> ✅ Active<br><strong>Repo:</strong> <a href="https://github.com/OpenSIN-AI/OpenSIN-backend/tree/main/services/sin-chrome-extension" target="_blank" rel="noreferrer">OpenSIN-backend/services/sin-chrome-extension</a><br><strong>HF MCP Server:</strong> <a href="https://huggingface.co/spaces/OpenJerro/opensin-bridge-mcp" target="_blank" rel="noreferrer">https://huggingface.co/spaces/OpenJerro/opensin-bridge-mcp</a></p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>OpenSIN Bridge is a <strong>Manifest V3 Chrome Extension</strong> that provides full browser automation capabilities for AI agents. It is <strong>better than Antigravity</strong> — more tools, more features, fully open source, no vendor lock-in.</p><h3 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>39 MCP Tools</strong></td><td>Tabs, navigation, DOM interaction, cookies, screenshots, storage, network, recording, stealth</td></tr><tr><td><strong>Content Scripts</strong></td><td>MAIN world injection on <code>&lt;all_urls&gt;</code> at <code>document_start</code></td></tr><tr><td><strong>webRequest</strong></td><td>Full request/response/error logging (500-entry buffer)</td></tr><tr><td><strong>Cookie CRUD</strong></td><td>Full Chrome Cookie API (get, set, delete, clear)</td></tr><tr><td><strong>declarativeNetRequest</strong></td><td>URL blocking capability</td></tr><tr><td><strong>Offscreen Document</strong></td><td>Persistent background processing (DOM parser, blob, storage)</td></tr><tr><td><strong>External Messaging</strong></td><td><code>onMessageExternal</code> for cross-origin communication</td></tr><tr><td><strong>Tab Events</strong></td><td>Auto-notify on tab load/create/close</td></tr><tr><td><strong>New Tab Override</strong></td><td>Custom OpenSIN landing page with brand icon</td></tr><tr><td><strong>Video Recording</strong></td><td>Screen recording via <code>chrome.tabCapture</code></td></tr><tr><td><strong>Stealth Mode</strong></td><td>Anti-detection: webdriver removal, plugin/language spoofing</td></tr></tbody></table><hr><h2 id="tool-reference-39-tools" tabindex="-1">Tool Reference (39 Tools) <a class="header-anchor" href="#tool-reference-39-tools" aria-label="Permalink to &quot;Tool Reference (39 Tools)&quot;">​</a></h2><h3 id="tab-management-5" tabindex="-1">Tab Management (5) <a class="header-anchor" href="#tab-management-5" aria-label="Permalink to &quot;Tab Management (5)&quot;">​</a></h3><p><code>tabs_list</code>, <code>tabs_create</code>, <code>tabs_update</code>, <code>tabs_close</code>, <code>tabs_activate</code></p><h3 id="navigation-4" tabindex="-1">Navigation (4) <a class="header-anchor" href="#navigation-4" aria-label="Permalink to &quot;Navigation (4)&quot;">​</a></h3><p><code>navigate</code>, <code>go_back</code>, <code>go_forward</code>, <code>reload</code></p><h3 id="dom-interaction-8" tabindex="-1">DOM Interaction (8) <a class="header-anchor" href="#dom-interaction-8" aria-label="Permalink to &quot;DOM Interaction (8)&quot;">​</a></h3><p><code>click_element</code>, <code>type_text</code>, <code>get_text</code>, <code>get_html</code>, <code>get_attribute</code>, <code>wait_for_element</code>, <code>execute_script</code>, <code>inject_css</code></p><h3 id="page-info-3" tabindex="-1">Page Info (3) <a class="header-anchor" href="#page-info-3" aria-label="Permalink to &quot;Page Info (3)&quot;">​</a></h3><p><code>get_page_info</code>, <code>get_all_links</code>, <code>get_all_inputs</code></p><h3 id="screenshot-2" tabindex="-1">Screenshot (2) <a class="header-anchor" href="#screenshot-2" aria-label="Permalink to &quot;Screenshot (2)&quot;">​</a></h3><p><code>screenshot</code>, <code>screenshot_full</code></p><h3 id="video-recording-3" tabindex="-1">Video Recording (3) <a class="header-anchor" href="#video-recording-3" aria-label="Permalink to &quot;Video Recording (3)&quot;">​</a></h3><p><code>start_recording</code>, <code>stop_recording</code>, <code>recording_status</code></p><h3 id="cookies-4" tabindex="-1">Cookies (4) <a class="header-anchor" href="#cookies-4" aria-label="Permalink to &quot;Cookies (4)&quot;">​</a></h3><p><code>get_cookies</code>, <code>set_cookie</code>, <code>delete_cookie</code>, <code>clear_cookies</code></p><h3 id="storage-3" tabindex="-1">Storage (3) <a class="header-anchor" href="#storage-3" aria-label="Permalink to &quot;Storage (3)&quot;">​</a></h3><p><code>storage_get</code>, <code>storage_set</code>, <code>storage_clear</code></p><h3 id="network-2" tabindex="-1">Network (2) <a class="header-anchor" href="#network-2" aria-label="Permalink to &quot;Network (2)&quot;">​</a></h3><p><code>get_network_requests</code>, <code>block_url</code></p><h3 id="stealth-mode-2" tabindex="-1">Stealth Mode (2) <a class="header-anchor" href="#stealth-mode-2" aria-label="Permalink to &quot;Stealth Mode (2)&quot;">​</a></h3><p><code>enable_stealth</code>, <code>stealth_status</code></p><h3 id="system-3" tabindex="-1">System (3) <a class="header-anchor" href="#system-3" aria-label="Permalink to &quot;System (3)&quot;">​</a></h3><p><code>health</code>, <code>list_tools</code>, <code>offscreen_status</code></p><hr><h2 id="comparison-opensin-bridge-vs-antigravity" tabindex="-1">Comparison: OpenSIN Bridge vs Antigravity <a class="header-anchor" href="#comparison-opensin-bridge-vs-antigravity" aria-label="Permalink to &quot;Comparison: OpenSIN Bridge vs Antigravity&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Antigravity</th><th>OpenSIN Bridge v2.5.0</th></tr></thead><tbody><tr><td>Tools</td><td>~15</td><td><strong>39</strong></td></tr><tr><td>Content Scripts</td><td>❌</td><td>✅ MAIN world</td></tr><tr><td>Cookie CRUD</td><td>❌</td><td>✅ Full API</td></tr><tr><td>webRequest Log</td><td>❌</td><td>✅ 500 entries</td></tr><tr><td>URL Blocking</td><td>❌</td><td>✅ declarativeNetRequest</td></tr><tr><td>Offscreen Docs</td><td>❌</td><td>✅ DOM Parser + Storage</td></tr><tr><td>Video Recording</td><td>✅</td><td>✅</td></tr><tr><td>Stealth Mode</td><td>❌</td><td>✅</td></tr><tr><td>Open Source</td><td>❌</td><td>✅</td></tr><tr><td>Cost</td><td>Free (preview)</td><td><strong>Free forever</strong></td></tr><tr><td>Vendor Lock-in</td><td>✅ Google only</td><td>❌ None</td></tr></tbody></table><hr><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/OpenSIN-AI/OpenSIN-backend.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OpenSIN-backend/services/sin-chrome-extension</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install.sh</span></span></code></pre></div><p>Or manually:</p><ol><li>Open <code>chrome://extensions/</code></li><li>Enable Developer mode</li><li>Click &quot;Load unpacked&quot;</li><li>Select: <code>extension/</code></li></ol><hr><h2 id="hf-mcp-server" tabindex="-1">HF MCP Server <a class="header-anchor" href="#hf-mcp-server" aria-label="Permalink to &quot;HF MCP Server&quot;">​</a></h2><p>The MCP Server runs on Hugging Face Spaces and is always online:</p><ul><li><strong>URL:</strong> <a href="https://huggingface.co/spaces/OpenJerro/opensin-bridge-mcp" target="_blank" rel="noreferrer">https://huggingface.co/spaces/OpenJerro/opensin-bridge-mcp</a></li><li><strong>Health:</strong> <a href="https://openjerro-opensin-bridge-mcp.hf.space/health" target="_blank" rel="noreferrer">https://openjerro-opensin-bridge-mcp.hf.space/health</a></li><li><strong>WebSocket:</strong> <code>wss://openjerro-opensin-bridge-mcp.hf.space</code></li></ul><p>The Chrome Extension auto-connects to this server on startup.</p><hr><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><h3 id="v2-5-0-2026-04-05-—-stealth-mode-video-recording" tabindex="-1">v2.5.0 (2026-04-05) — Stealth Mode + Video Recording <a class="header-anchor" href="#v2-5-0-2026-04-05-—-stealth-mode-video-recording" aria-label="Permalink to &quot;v2.5.0 (2026-04-05) — Stealth Mode + Video Recording&quot;">​</a></h3><ul><li>✅ start_recording / stop_recording / recording_status</li><li>✅ enable_stealth / stealth_status</li><li>✅ 39 Tools total</li></ul><h3 id="v2-4-1-2026-04-04-—-hf-mcp-url-fixed" tabindex="-1">v2.4.1 (2026-04-04) — HF MCP URL Fixed <a class="header-anchor" href="#v2-4-1-2026-04-04-—-hf-mcp-url-fixed" aria-label="Permalink to &quot;v2.4.1 (2026-04-04) — HF MCP URL Fixed&quot;">​</a></h3><h3 id="v2-4-0-2026-04-04-—-hf-mcp-websocket-mode" tabindex="-1">v2.4.0 (2026-04-04) — HF MCP WebSocket Mode <a class="header-anchor" href="#v2-4-0-2026-04-04-—-hf-mcp-websocket-mode" aria-label="Permalink to &quot;v2.4.0 (2026-04-04) — HF MCP WebSocket Mode&quot;">​</a></h3><h3 id="v2-3-0-2026-04-04-—-pure-chrome-api-mode" tabindex="-1">v2.3.0 (2026-04-04) — Pure Chrome API Mode <a class="header-anchor" href="#v2-3-0-2026-04-04-—-pure-chrome-api-mode" aria-label="Permalink to &quot;v2.3.0 (2026-04-04) — Pure Chrome API Mode&quot;">​</a></h3><h3 id="v2-0-0-2026-04-04-—-initial-release" tabindex="-1">v2.0.0 (2026-04-04) — Initial Release <a class="header-anchor" href="#v2-0-0-2026-04-04-—-initial-release" aria-label="Permalink to &quot;v2.0.0 (2026-04-04) — Initial Release&quot;">​</a></h3><hr><h2 id="relevante-mandate" tabindex="-1">Relevante Mandate <a class="header-anchor" href="#relevante-mandate" aria-label="Permalink to &quot;Relevante Mandate&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mandat</th><th>Priority</th><th>Regel</th></tr></thead><tbody><tr><td><strong>Bun-Only</strong></td><td>-1.5</td><td><code>bun install</code> / <code>bun run</code> statt npm</td></tr><tr><td><strong>Annahmen-Verbot</strong></td><td>-5.0</td><td>KEINE Diagnose ohne Beweis</td></tr><tr><td><strong>Test-Beweis-Pflicht</strong></td><td>0.0</td><td>KEIN &quot;Done&quot; ohne echten Test-Lauf</td></tr></tbody></table><p>→ <a href="/best-practices/code-quality.html">Alle Mandate</a></p>`,56)])])}const b=t(n,[["render",d]]);export{p as __pageData,b as default};
